import React from 'react';
import { makeStyles } from '@material-ui/core/styles';
import Paper from '@material-ui/core/Paper';
import Tabs from '@material-ui/core/Tabs';
import Tab from '@material-ui/core/Tab';
import { Link } from 'react-router-dom';
import Typography from '@material-ui/core/Typography';
import Grid from '@material-ui/core/Grid';


const useStyles = makeStyles((theme) => ({
    root: {
        marginTop: '4.9rem',
        position: 'fixed',
        zIndex: 1,
        width: '100%',
    },
    colorPrimary: {
        color: '#fff',
        background: 'linear-gradient(#555, #222)',
        boxShadow: '0 1px 1px #777, 0 1px 0 #666 inset',
    },
}));

export default function MenuCrop(props) {
    const classes = useStyles();
    const valueMenu = props.valueMenu;
    const setValueMenu = props.setValueMenu;
    const handleScroll = (e) => {
        const idx = e.currentTarget.id;
        const section = (document.getElementById(`section${idx}`).offsetTop) - 120;
        window.scrollTo({
            top: section,
            behavior: "smooth"
        })
    }


    return (
        <Paper className={classes.root}>
            <Grid container position="static" className={classes.colorPrimary}>
                <Grid item lg={2}>
                    <Typography variant="h5" component="h2" style={{opacity: '0.7', 
                                                                    alignItems: 'center',
                                                                    fontWeight: '500',
                                                                    textTransform: 'uppercase', 
                                                                    paddingTop: '0.9rem', 
                                                                    paddingLeft: '0.5rem', 
                                                                    fontSize: '0.85rem', }}>Мультикомплекси</Typography>
                </Grid>
                <Grid item lg={10}>
                <Tabs
                    value={valueMenu}
                    centered
                    selected={false}
                    variant="scrollable"
                    scrollButtons="auto"
                >
                    
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="1" component={Link} to='/complex/complex-femoco' label="Mo-Fe-Co" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="2" component={Link} to='/complex/complex-mnzn' label="Мn-Zn" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="3" component={Link} to='/complex/complex-mocofemn' label="Mo-Co-Fe-Mn" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="4" component={Link} to='/complex/complex-bcu' label="B-Сu" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="5" component={Link} to='/complex/complex-mg' label="Mg" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="2" component={Link} to='/complex/complex-b' label="B" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="3" component={Link} to='/complex/complex-zn' label="Zn" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="4" component={Link} to='/complex/complex-bmo' label="B-Mo" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="5" component={Link} to='/complex/complex-mn' label="Mn" />
                </Tabs>
                </Grid>
            </Grid>
        </Paper>
    );
}