import React from 'react';
import { withStyles, makeStyles } from '@material-ui/core/styles';
import Table from '@material-ui/core/Table';
import TableBody from '@material-ui/core/TableBody';
import TableCell from '@material-ui/core/TableCell';
import TableContainer from '@material-ui/core/TableContainer';
import TableHead from '@material-ui/core/TableHead';
import TableRow from '@material-ui/core/TableRow';
import Paper from '@material-ui/core/Paper';
import CalcTable from './CalcTable';

const useStyles = makeStyles((theme) => ({
    root: {
        paddingLeft: '1rem',
    },
    textContainer: {
        padding: '1rem',
    },
    listIcon: {
        minWidth: '19px',
    },
    advTitle: {
        color: '#00823c',
        paddingTop: 0,
        paddingBottom: '8px',
    },
    titleBox: {
        width: 'inherit',
        position: 'relative',
    },
    boxPosition: {
        color: '#ffff',
        background: 'rgba(0, 130, 90, 0.7)',
        position: 'absolute',
        bottom: '1rem',
        width: 'inherit',
    },
    wrapTable: {
        marginBottom: '2rem',
    },
}))
const StyledTableCell = withStyles(theme => ({

    head: {
        backgroundColor: '#00823c',
        color: theme.palette.common.white,
        fontWeight: 600,
        width: '1rem',
    },
    body: {
        fontSize: 14,
    },

}))(TableCell);

const ApplicationTable = (props) => {
    const classes = useStyles();
    const data = props.data;
    const align1='center' 
    const align2='center'
    let calc = []
    data.Crops.map((elem) => {
            calc.push([elem]);
            return calc
    });
    
    data.CropsPeriods.map((elem,i) => {
        let str = "";
       
        elem.map((elem)=>{
            str +=elem+', '
            
            return str
        })
        calc[i].push(str)
        return calc
    });
    

    return (
        <TableContainer component={Paper} className={classes.wrapTable}>
            <Table className={classes.table} aria-label="customized table">
                <TableHead>
                    <TableRow>
                        <StyledTableCell align="center" className={classes.align} >Культури</StyledTableCell>
                        <StyledTableCell align="center" colSpan={1} className={classes.align} >Застосування за фазами вегетації</StyledTableCell>
                    </TableRow>
                </TableHead>
                <TableBody>
                    <CalcTable calc={calc}
                                align1={align1}
                                align2={align2}/>
                </TableBody>
            </Table>
        </TableContainer>
    )
}
export default ApplicationTable;