import React from 'react';
import { withStyles} from '@material-ui/core/styles';
import TableRow from '@material-ui/core/TableRow';
import TableCell from '@material-ui/core/TableCell';



const StyledTableCell = withStyles(theme => ({

    head: {
        backgroundColor: '#00823c',
        color: theme.palette.common.white,
        fontWeight: 600,
    },
    body: {
        fontSize: 14,
    },
}))(TableCell);

const StyledTableRow = withStyles(theme => ({
    root: {
        '&:nth-of-type(odd)': {
            backgroundColor: '#f1f5dc',
            borderBottom: '2px solid black', /* Толщина линии внизу */
            //borderBottomStyle: 'solid', /* Стиль линии внизу */
            //borderBottomColor: 'white',
        },
        '&:nth-of-type(even)': {
            backgroundColor: '#f1f5dc',
           // backgroundColor: '#c5dfb8',
        },
    },
}))(TableRow);


const CalcTable = (props)=>{
    const calc =props.calc;
    const align1=props.align1;
    const align2 = props.align2;
    
    return(
        <>
            {calc.map((calc)=>(
            
                <StyledTableRow>
                    {calc.map((complex, i) => (
                        i === 0 ? <StyledTableCell align={align1} style={{ borderBottom: '4px solid #00823C' }}>{complex}</StyledTableCell> : <StyledTableCell align={align2} style={{ borderBottom: '4px solid #00823C' }}>{complex}</StyledTableCell>

                    ))}
                </StyledTableRow>
        
            ))}
        </>
            
    )
};
export default CalcTable;