import React from 'react';
import { makeStyles } from '@material-ui/core/styles';
import Container from '@material-ui/core/Container';
import Paper from '@material-ui/core/Paper';
import Typography from '@material-ui/core/Typography';
import Grid from '@material-ui/core/Grid';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemIcon from '@material-ui/core/ListItemIcon';
import ListItemText from '@material-ui/core/ListItemText';
import Button from '@material-ui/core/Button';

import { ReactComponent as Rect } from '../img/rect.svg';
import CompositionTable from './CompositionTable';
import ApplicationTable from './ApplicationTable';
import ComplexModalOrder from './ComplexModalOrder'

const useStyles = makeStyles((theme) => ({

    advTitle: {
        color: '#00823c',
        paddingTop: 0,
        paddingBottom: '8px',
    },
    root: {
        fontSize: '2.5rem',
        paddingTop: '3rem',
    },
    padding: {
        paddingTop: 0,
        paddingBottom: 0,
    },
    paddingItem: {
        paddingTop: 0,
        paddingBottom: 0,
    },
    wrap: {
        fontColor: '02833e',
        [theme.breakpoints.down("sm")]: {
            maxWidth: 525,
            fontSize: '2rem',
            
        },
        paddingBottom: '2rem',
        width: 'inherit',
    },
    img: {
        height:'47%',
        marginLeft: '4rem',
        [theme.breakpoints.down("sm")]: {
        width: '21rem',
        }
    },
    textContainer: {
        padding: '1rem',
    },
    order: {
        backgroundColor: '#ffa000',
        color: '#ffffff',
        margin: '0.4rem 0.4rem 2rem 0.4rem',
    },
}))

const ComplexPage = (props) => {
    const classes = useStyles();
    const data = props.data[props.complex];
    const [open, setOpen] = React.useState(false);
    const [modal, setModal] = React.useState(0);
    const handleClickOpen = (e) => {
        const idx = parseInt(e.currentTarget.id.match(/(\d+\.\d+)|(\d+)/g));
        setOpen(true);
        setModal(idx);


    };
    const handleClose = () => {
        setOpen(false);
    };
    console.log(data)
    return(
    <div style={{ paddingTop: '8rem', }}>
        <Container className={classes.wrap} id={`complexpage${data.id}`}>
            <Paper  elevation={3} >
                    <img style={{ height: '11rem', objectFit: 'cover', width:'100%'}} src={`/static/img/wheat.jpg`} alt={data.title} />
                    <Typography variant="h1" align='center' className={classes.root}>{data.title}</Typography>
                    <Grid container direction="row" justify="center" style={{ padding: '3rem',}}>
                    <Grid item lg={6} md={12} xs={12}>
                        <img className={classes.img} src={`/static/img/${data.title.split(' ')[1]}.png`} alt={data.title} />
                        <CompositionTable data={data} />
                    </Grid>
                    <Grid item lg={6} md={12} xs={12}>                   
                        <Typography variant="h6" className={classes.textContainer + ' ' + classes.advTitle}>{data.ApplicationTitle}</Typography>
                        {data.ApplicationDesc.map((list) => (
                            < List className={classes.padding}>
                                <ListItem className={classes.paddingItem}>
                                    <ListItemIcon className={classes.listIcon}>
                                        <Rect />
                                    </ListItemIcon>
                                    <ListItemText primary={list} />
                                </ListItem>
                            </List>
                        ))}
                        <Typography variant="h6" className={classes.textContainer + ' ' + classes.advTitle}>{data.featuresTitle}</Typography>
                        {data.featuresDesc.map((list) => (
                            < List className={classes.padding}>
                                <ListItem className={classes.paddingItem}>
                                    <ListItemIcon className={classes.listIcon}>
                                        <Rect />
                                    </ListItemIcon>
                                    <ListItemText primary={list} />
                                </ListItem>
                            </List>
                        ))}
                    </Grid>
                    
                    {/*<Grid item sm={12}>
                        
                        </Grid>*/}
                </Grid> 
                
                <ApplicationTable data={data}/>
                <Grid item xs={12} style={{ textAlign: 'center' }}>
                    <Button size="large" className={classes.order} onClick={handleClickOpen} id={data.id}>
                        Замовити
                    </Button>
                </Grid>
                <ComplexModalOrder open={open}
                    id={modal}
                    onClose={handleClose}
                    title={data.title}
                />
            </Paper>
        </Container>
    </div>
)
}
export default ComplexPage;