import Data from '../data/data.json';
const calcProgram=(check, value, data, title, calc )=>{
    
    let titlePeriod=[]
    let table = [];
    let tableLine = [];
    let total = 0;
    let inPack = 0;
    let prices=""
    
    for (const prop in check)
    {  
        if (check[prop]) { title.push(data.nameperiods[prop])};
        if (check[prop]) { titlePeriod.push(prop)};
        
    };
    title.push('Всього');
    title.push('З урахуванням пакування');
    title.push('Ціна за літр');
    title.push('Сума');

    titlePeriod.map((Period)=>{
        let table1 = [];    
            table1.push(Object.getOwnPropertyNames(data.periods[Period])) 
        table1.map((table1)=>{
            for (let i=0; i<table1.length;i++){
            if (!table.includes(table1[i])) {table.push(table1[i])};
            }
            return table;
        })
        return table;
    })
    table.map((table)=>{
        tableLine.push([table]);
        return tableLine;
    })
    titlePeriod.map((title)=>{
        for (let i = 0; i < tableLine.length; i++) {
            if (typeof data.periods[title][tableLine[i][0]] !== "undefined"){
                    tableLine[i].push(`${data.periods[title][tableLine[i][0]]} л/га`)
                } else { tableLine[i].push("-");
                }
            }
         return tableLine;   
    })
    
    tableLine.map((tableLine,i)=>{
        total = 0;
        prices=""
        calc.push(tableLine)
        tableLine.map((tableLine) => {
            if (!isNaN(parseFloat(tableLine.match(/(\d+\.\d+)|(\d+)/g)))){
                total += parseFloat(tableLine.match(/(\d+\.\d+)|(\d+)/g))
            }
            return total
        })
        prices = calc[i][0];
        calc[i].push(`${(total*value).toFixed(2)} л.`);
        inPack = ((Math.ceil(total*value / 10) ) * 10).toFixed(2);
        calc[i].push(`${inPack} л.`);
        calc[i].push(`${Data[1].drug[prices]['price']} грн.`)
        calc[i].push(`${(Data[1].drug[prices]['price'] * inPack).toFixed(2)} грн.`)
        return calc;
    })
    
    return calc;
};
export default calcProgram;